/* ══ Chat: Messages, Thinking, Exec Cards, Approval Cards, Token Bar ══ */

.status-dot {
  background: var(--muted);
  border-radius: 50%;
  flex-shrink: 0;
  width: 8px;
  height: 8px;
  transition: background 0.3s;
}

.status-dot.connected {
  background: var(--ok);
  animation: 1.8s ease-out infinite status-live-pulse;
}

.status-dot.connecting {
  background: var(--warn);
  animation: 1s infinite pulse;
}

.status-text-live {
  color: var(--ok) !important;
  font-weight: 600;
  text-shadow: 0 0 8px rgba(34, 197, 94, 0.45);
}

@keyframes status-live-pulse {
  0% {
    box-shadow: 0 0 0 0 rgba(34, 197, 94, 0.55);
  }
  70% {
    box-shadow: 0 0 0 8px rgba(34, 197, 94, 0);
  }
  100% {
    box-shadow: 0 0 0 0 rgba(34, 197, 94, 0);
  }
}

.msg {
  border-radius: var(--radius);
  word-wrap: break-word;
  white-space: pre-wrap;
  max-width: 80%;
  padding: 10px 14px;
  font-size: 0.9rem;
  line-height: 1.6;
  animation: 0.2s ease-out msg-in;
}

.msg.user {
  background: var(--user-bg);
  border: 1px solid var(--user-border);
  color: var(--text);
  align-self: flex-end;
}

.msg.assistant {
  background: var(--assistant-bg);
  border: 1px solid var(--assistant-border);
  color: var(--text);
  align-self: flex-start;
}


.msg.system {
  color: var(--muted);
  background: 0 0;
  align-self: center;
  padding: 4px 0;
  font-size: 0.8rem;
}

.msg.system.system-notice {
  background: var(--surface2);
  background: color-mix(in srgb, var(--surface2) 85%, transparent);
  border: 1px solid var(--border);
  border-color: color-mix(in srgb, var(--border-strong) 65%, transparent);
  border-radius: 999px;
  align-items: center;
  gap: 6px;
  max-width: min(88%, 640px);
  padding: 5px 10px;
  white-space: normal;
  display: inline-flex;
}

.msg.system.system-notice strong {
  color: var(--text);
  font-weight: 600;
}

.msg.system.system-notice.system-notice-sandbox::before {
  content: "";
  background: var(--muted);
  border-radius: 999px;
  flex-shrink: 0;
  width: 6px;
  height: 6px;
}

.msg.system.system-notice.system-notice-sandbox.is-enabled {
  background: var(--surface2);
  background: color-mix(in srgb, var(--ok) 8%, var(--surface2));
  border-color: color-mix(in srgb, var(--ok) 28%, var(--border));
}

.msg.system.system-notice.system-notice-sandbox.is-enabled::before {
  background: var(--ok);
}

.msg.system.system-notice.system-notice-sandbox.is-disabled {
  background: var(--surface2);
  background: color-mix(in srgb, var(--warn) 8%, var(--surface2));
  border-color: color-mix(in srgb, var(--warn) 24%, var(--border));
}

.msg.system.system-notice.system-notice-sandbox.is-disabled::before {
  background: var(--warn);
}

.msg.error {
  color: var(--error);
  background: 0 0;
  align-self: center;
  padding: 4px 0;
  font-size: 0.8rem;
}

.msg.error-card {
  background: var(--surface);
  border: 1px solid var(--error);
  border-radius: 8px;
  align-self: center;
  align-items: flex-start;
  gap: 10px;
  max-width: 420px;
  padding: 12px 16px;
  display: flex;
}

.error-icon {
  flex-shrink: 0;
  font-size: 1.4rem;
  line-height: 1;
}

.error-body {
  flex: 1;
  min-width: 0;
}

.error-title {
  color: var(--error);
  margin-bottom: 2px;
  font-size: 0.85rem;
  font-weight: 600;
}

.error-detail {
  color: var(--fg);
  opacity: 0.85;
  font-size: 0.8rem;
}

.error-countdown {
  color: var(--muted);
  white-space: nowrap;
  flex-shrink: 0;
  align-self: center;
  font-size: 0.75rem;
}

.error-countdown.reset-ready {
  color: var(--success, #22c55e);
  font-weight: 600;
}

/* ── Thinking ── */

.msg.thinking {
  background: var(--assistant-bg);
  border: 1px solid var(--assistant-border);
  align-items: center;
  padding: 14px 18px;
  display: flex;
}

.msg.thinking.session-loading {
  gap: 10px;
  align-self: center;
}

.session-loading-label {
  color: var(--muted);
  font-size: 0.78rem;
  letter-spacing: 0.01em;
}

.thinking-dots {
  align-items: center;
  gap: 5px;
  display: flex;
}

.thinking-dots span {
  background: var(--muted);
  border-radius: 50%;
  width: 7px;
  height: 7px;
  animation: 1.2s ease-in-out infinite dot-bounce;
}

.thinking-dots span:nth-child(2) { animation-delay: 0.15s; }
.thinking-dots span:nth-child(3) { animation-delay: 0.3s; }

.thinking-text {
  color: var(--muted);
  white-space: pre-wrap;
  text-overflow: ellipsis;
  -webkit-line-clamp: 2;
  -webkit-box-orient: vertical;
  font-size: 0.82rem;
  font-style: italic;
  line-height: 1.4;
  animation: 2s ease-in-out infinite thinking-pulse;
  display: -webkit-box;
  overflow: hidden;
}

@keyframes thinking-pulse {
  0%, to { opacity: 0.6; }
  50% { opacity: 1; }
}

/* ── Tool events ── */

.msg.tool-event {
  font-family: var(--font-mono);
  font-size: 0.78rem;
}

.msg.tool-ok { color: var(--ok); }
.msg.tool-err { color: var(--error); }

/* ── Exec cards ── */

.msg.exec-card {
  background: var(--surface);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  white-space: normal;
  flex-direction: column;
  align-self: flex-start;
  gap: 4px;
  max-width: 70%;
  padding: 8px 12px;
  display: flex;
}

.msg.exec-card.exec-ok { border-color: var(--border); }
.msg.exec-card.exec-err { border-color: var(--error); }

.exec-prompt {
  font-family: var(--font-mono);
  color: var(--text);
  font-size: 0.8rem;
  line-height: 1.4;
}

.exec-prompt-char {
  color: var(--ok);
  -webkit-user-select: none;
  user-select: none;
  font-weight: 600;
}

.exec-card.exec-err .exec-prompt-char { color: var(--error); }

.exec-status {
  color: var(--muted);
  font-size: 0.72rem;
  font-style: italic;
}

.exec-output {
  font-family: var(--font-mono);
  color: var(--text);
  background: var(--bg);
  border: 1px solid var(--border);
  white-space: pre;
  border-radius: 4px;
  max-height: 200px;
  margin: 0;
  padding: 6px 8px;
  font-size: 0.78rem;
  line-height: 1.45;
  overflow: auto;
}

.exec-output.exec-stderr { color: var(--warn); }

.exec-exit {
  font-family: var(--font-mono);
